css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #070b18; color: white; }
nav { display: flex; align-items: center; justify-content: space-between; padding: 0 72px; height: 68px; border-bottom: 1px solid rgba(255,255,255,0.07); }
.logo { font-size: 22px; font-weight: 800; color: #a855f7; }
.links { display: flex; gap: 28px; } .links a { color: #6b7280; text-decoration: none; font-weight: 500; }
.nav-cta { padding: 10px 20px; border-radius: 10px; border: 1px solid rgba(168,85,247,0.4); background: rgba(168,85,247,0.1); color: #c084fc; font-weight: 700; cursor: pointer; }
.hero { text-align: center; padding: 60px 72px 40px; }
h1 { font-size: 52px; font-weight: 900; letter-spacing: -2px; margin-bottom: 14px; }
.hero p { color: #6b7280; font-size: 17px; margin-bottom: 28px; }
.billing-toggle { display: inline-flex; align-items: center; gap: 14px; background: rgba(255,255,255,0.05); padding: 10px 20px; border-radius: 40px; }
.billing-toggle span { font-size: 15px; font-weight: 600; color: #6b7280; cursor: pointer; }
.billing-toggle span.active { color: white; }
.toggle { width: 44px; height: 24px; border-radius: 12px; background: rgba(255,255,255,0.1); cursor: pointer; position: relative; transition: background 0.3s; } .toggle.on { background: #a855f7; }
.toggle-ball { width: 18px; height: 18px; border-radius: 50%; background: white; position: absolute; top: 3px; left: 3px; transition: left 0.3s; } .toggle.on .toggle-ball { left: 23px; }
.save-badge { background: rgba(34,197,94,0.2); color: #22c55e; padding: 2px 8px; border-radius: 10px; font-size: 12px; font-weight: 700; }
.plans { display: grid; grid-template-columns: repeat(3, 1fr); gap: 20px; padding: 20px 72px 80px; max-width: 1100px; margin: 0 auto; }
.plan { background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.08); border-radius: 24px; padding: 32px; position: relative; transition: transform 0.2s; } .plan:hover { transform: translateY(-4px); }
.plan.featured { background: rgba(168,85,247,0.08); border-color: rgba(168,85,247,0.4); transform: scale(1.04); }
.popular-tag { position: absolute; top: -14px; left: 50%; transform: translateX(-50%); background: linear-gradient(135deg, #a855f7, #ec4899); color: white; padding: 5px 18px; border-radius: 20px; font-size: 12px; font-weight: 800; white-space: nowrap; }
.plan-icon { font-size: 36px; margin-bottom: 14px; }
.plan h2 { font-size: 24px; font-weight: 800; margin-bottom: 6px; }
.plan-desc { color: #6b7280; font-size: 14px; margin-bottom: 20px; }
.plan-price { margin-bottom: 24px; display: flex; align-items: baseline; gap: 4px; }
.price { font-size: 42px; font-weight: 900; }
.plan-price span { color: #6b7280; font-size: 15px; }
.features { list-style: none; display: flex; flex-direction: column; gap: 10px; margin-bottom: 28px; }
.features li { font-size: 14px; } .yes { color: rgba(255,255,255,0.85); } .no { color: #374151; }
.plan-btn { width: 100%; height: 50px; border-radius: 14px; font-size: 15px; font-weight: 700; cursor: pointer; transition: all 0.2s; }
.plan-btn.primary { border: none; background: linear-gradient(135deg, #a855f7, #ec4899); color: white; }
.plan-btn.outline { border: 1px solid rgba(255,255,255,0.2); background: transparent; color: white; } .plan-btn.outline:hover { background: rgba(255,255,255,0.08); }
.faq { padding: 0 72px 80px; max-width: 760px; margin: 0 auto; }
.faq h2 { font-size: 32px; font-weight: 800; margin-bottom: 24px; }
.faq-item { border: 1px solid rgba(255,255,255,0.08); border-radius: 14px; margin-bottom: 10px; overflow: hidden; }
.faq-q { padding: 18px 20px; font-size: 15px; font-weight: 600; cursor: pointer; display: flex; justify-content: space-between; align-items: center; } .faq-arrow { color: #a855f7; font-size: 12px; transition: transform 0.3s; }
.faq-a { padding: 0 20px; max-height: 0; overflow: hidden; transition: all 0.3s; font-size: 14px; color: #6b7280; line-height: 1.7; }
.faq-item.open .faq-a { padding: 0 20px 18px; max-height: 200px; }
.faq-item.open .faq-arrow { transform: rotate(180deg); }

