let yearly = false;
const prices = { monthly: ['₺99','₺299','₺999'], yearly: ['₺79','₺239','₺799'] };
function toggleBilling() {
  yearly = !yearly;
  const toggle = document.querySelector('.toggle');
  const ball = document.getElementById('ball');
  toggle.classList.toggle('on', yearly);
  document.getElementById('monthly-label').classList.toggle('active', !yearly);
  document.getElementById('yearly-label').classList.toggle('active', yearly);
  ['p1','p2','p3'].forEach((id,i) => { const el = document.getElementById(id); el.style.transform = 'scale(0.8)'; el.style.opacity = '0'; setTimeout(() => { el.textContent = yearly ? prices.yearly[i] : prices.monthly[i]; el.style.transform = 'scale(1)'; el.style.opacity = '1'; }, 200); el.style.transition = 'all 0.2s'; });
}
function toggleFaq(el) { el.classList.toggle('open'); }
function select(btn) { const prev = btn.textContent; btn.textContent = '✓ Seçildi!'; btn.style.background = '#22c55e'; btn.style.borderColor = '#22c55e'; btn.style.color = 'white'; setTimeout(() => { btn.textContent = prev; btn.style.background = ''; btn.style.borderColor = ''; btn.style.color = ''; }, 2000); }
